package main

import (
	"context"
	"errors"
	"log"
	"net"
	"sync"
	"sync/atomic"
	"time"

	"google.golang.org/grpc"

	bankingpb "example.com/banking/proto"
)

type account struct {
	ID       string
	Balance  int64
	Currency string
}

type transactionServer struct {
	bankingpb.UnimplementedTransactionServiceServer
	mu             sync.Mutex
	accounts       map[string]*account
	transactionSeq uint64
}

func newTransactionServer() *transactionServer {
	return &transactionServer{
		accounts: map[string]*account{
			"acct_1": {ID: "acct_1", Balance: 100000, Currency: "USD"},
			"acct_2": {ID: "acct_2", Balance: 50000, Currency: "USD"},
			"acct_3": {ID: "acct_3", Balance: 70000, Currency: "USD"},
		},
	}
}

func (s *transactionServer) CreateTransaction(ctx context.Context, req *bankingpb.CreateTransactionRequest) (*bankingpb.CreateTransactionResponse, error) {
	if req.GetFromAccountId() == "" || req.GetToAccountId() == "" {
		return nil, errors.New("from_account_id and to_account_id are required")
	}
	if req.GetFromAccountId() == req.GetToAccountId() {
		return nil, errors.New("from and to accounts must be different")
	}
	if req.GetAmount() <= 0 {
		return nil, errors.New("amount must be greater than zero")
	}
	if req.GetCurrency() == "" {
		return nil, errors.New("currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	from, ok := s.accounts[req.GetFromAccountId()]
	if !ok {
		return nil, errors.New("source account not found")
	}
	to, ok := s.accounts[req.GetToAccountId()]
	if !ok {
		return nil, errors.New("destination account not found")
	}
	if from.Currency != req.GetCurrency() || to.Currency != req.GetCurrency() {
		return nil, errors.New("currency mismatch")
	}
	if from.Balance < req.GetAmount() {
		return nil, errors.New("insufficient funds")
	}

	from.Balance -= req.GetAmount()
	to.Balance += req.GetAmount()

	txID := atomic.AddUint64(&s.transactionSeq, 1)

	return &bankingpb.CreateTransactionResponse{
		TransactionId: formatTransactionID(txID),
		Status:        "COMPLETED",
	}, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *bankingpb.GetBalanceRequest) (*bankingpb.GetBalanceResponse, error) {
	if req.GetAccountId() == "" {
		return nil, errors.New("account_id is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	acct, ok := s.accounts[req.GetAccountId()]
	if !ok {
		return nil, errors.New("account not found")
	}

	return &bankingpb.GetBalanceResponse{
		AccountId: acct.ID,
		Balance:   acct.Balance,
		Currency:  acct.Currency,
	}, nil
}

func formatTransactionID(seq uint64) string {
	return time.Now().UTC().Format("20060102T150405") + "-" + itoa(seq)
}

func itoa(v uint64) string {
	if v == 0 {
		return "0"
	}
	var buf [20]byte
	i := len(buf)
	for v > 0 {
		i--
		buf[i] = byte('0' + v%10)
		v /= 10
	}
	return string(buf[i:])
}

